// mm/src/api/refresh.js
import axios from 'axios';
import { getRefreshToken, saveAuth } from '../utils/auth';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

/**
 * refresh.php
 * Body: multipart/form-data with key "refreshToken"
 * No Authorization header required
 *
 * Expected response (example):
 *  { success: true, accessToken: "...", refreshToken: "..."? }
 */
export async function refreshTokens() {
  const refreshToken = getRefreshToken();
  if (!refreshToken) {
    throw new Error('Missing refresh token');
  }

  const url = `${API_BASE}/refresh.php`;

  const form = new FormData();
  form.append('refreshToken', refreshToken);

  const res = await axios.post(url, form, {
    headers: {
      Accept: 'application/json',
    },
  });

  const data = res.data || {};

  // Adjust these keys if your backend uses different casing
  const newAccessToken = data.accessToken ?? data.AccessToken ?? null;
  const newRefreshToken = data.refreshToken ?? data.RefreshToken ?? null;

  if (!newAccessToken) {
    throw new Error(data?.message || 'refresh.php did not return accessToken');
  }

  // Save tokens + createdAt using your centralized auth storage
  saveAuth({
    accessToken: newAccessToken,
    refreshToken: newRefreshToken || refreshToken,
  });

  return {
    accessToken: newAccessToken,
    refreshToken: newRefreshToken || refreshToken,
  };
}

/**
 * Retry wrapper: if request fails with 401, refresh and retry once.
 */
export async function withAuthRetry(requestFn) {
  try {
    return await requestFn();
  } catch (err) {
    const status = err?.response?.status;

    if (status === 401) {
      await refreshTokens();
      return await requestFn();
    }

    throw err;
  }
}
